fn stops(name: &str) -> &'static [Stop] {
    match RAMPS.binary_search_by(|(n, _)| (*n).cmp(name)) {
        Ok(i) => RAMPS[i].1,
        // "grey", "", and unknown names.
        Err(_) => GRAY,
    }
}

